#include<bits/stdc++.h>
using namespace std;
struct node
{
    int l,r,lson,rson;
    long long lmax,rmax,sum;
    node()
    {
        lmax=rmax=sum=0;
    }
}a[3000010];
long long cnt,root[100010];
void pushup(long long x)
{
    a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
    a[x].lmax=max(a[a[x].lson].lmax,a[a[x].lson].sum+a[a[x].rson].lmax);
    a[x].rmax=max(a[a[x].rson].rmax,a[a[x].lson].rmax+a[a[x].rson].sum);
}
void pushup(node &x,node l,node r)
{
    x.lmax=max(l.lmax,l.sum+r.lmax);
    x.rmax=max(r.rmax,l.rmax+r.sum);
    x.sum=l.sum+r.sum;
}
long long build(long long l,long long r)
{
    long long x=++cnt;
    a[x].l=l;
    a[x].r=r;
    if(l==r)
    {
        a[x].lmax=a[x].rmax=a[x].sum=1;
        return x;
    }
    long long mid=(l+r)>>1;
    a[x].lson=build(l,mid);
    a[x].rson=build(mid+1,r);
    pushup(x);
    return x;
}
long long update(long long x,long long p,long long v)
{
    if(a[x].l>p||a[x].r<p)
    {
        return x;
    }
    long long now=++cnt;
    a[now]=a[x];
    if(a[x].l==a[x].r)
    {
        a[now].sum=a[now].lmax=a[now].rmax=v;
        return now;
    }
    a[now].lson=update(a[x].lson,p,v);
    a[now].rson=update(a[x].rson,p,v);
    pushup(now);
    return now;
}
node query(long long x,long long l,long long r)
{
    if(l<=a[x].l&&a[x].r<=r)
    {
        return a[x];
    }
    long long mid=(a[x].l+a[x].r)>>1;
    if(l<=mid&&mid<r)
    {
        node ans;
        pushup(ans,query(a[x].lson,l,r),query(a[x].rson,l,r));
        return ans;
    }
    else if(l<=mid)
    {
        return query(a[x].lson,l,r);
    }
    else
    {
        return query(a[x].rson,l,r);
    }
}
long long q[101],b[100010],id[100010];
bool check(long long mid)
{
    int val=0;
    if(q[1]+1<=q[2]-1)
    {
        val+=query(root[mid],q[1]+1,q[2]-1).sum;
    }
    val+=query(root[mid],q[0],q[1]).rmax;
    val+=query(root[mid],q[2],q[3]).lmax;
    return val>=0;
}
bool cmp(long long x,long long y)
{
    return b[x]<b[y];
}
int main()
{
    long long n;
    scanf("%lld",&n);
    root[1]=build(1,n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
        id[i]=i;
    }
    sort(id+1,id+1+n,cmp);
    for(long long i=2;i<=n;i++)
    {
        root[i]=update(root[i-1],id[i-1],-1);
    }
    long long Q,ans=0;
    scanf("%lld",&Q);
    while(Q--)
    {
        for(long long i=0;i<4;i++)
        {
            scanf("%lld",&q[i]);
            q[i]=(q[i]+ans)%n+1;
        }
        sort(q,q+4);
        long long l=1,r=n;
        while(l<=r)
        {
            long long mid=(l+r)>>1;
            if(check(mid))
            {
                ans=b[id[mid]];
                l=mid+1;
            }
            else
            {
                r=mid-1;
            }
        }
        printf("%lld\n",ans);
    }
    return 0;
}
